Value.Calculation:
Let([
	ts = GetAsTimestamp ( Get ( CurrentHostTimestamp ) ) ;
	d = GetAsDate ( ts ) ;
	t = GetAsTime ( ts )
] ;
	Year ( d ) & "-" & Right ( "0" & Month ( d ) ; 2 ) & "-" & Right ( "0" & Day ( d ) ; 2 ) & "T" &
	Right ( "0" & Hour ( t ) ; 2 ) & ":" & Right ( "0" & Minute ( t ) ; 2 ) & ":" & Right ( "0" & Int ( Seconds ( t ) ) ; 2 ) & "Z"
)

JSONSetElement ( "{}" ;
[ "vorgang_id" ; JSONGetElement ( $json ; "[" & $idx & "].vorgang_id" ) ; JSONString ] ;
[ "vertragsbesitzer_id" ; Lower ( $$INHABER_ID ) ; JSONString ] ;
[ "vertrag" ; JSONGetElement ( $json ; "[" & $idx & "].vertrag" ) ; JSONString ] ;
[ "vorgang_art" ; JSONGetElement ( $json ; "[" & $idx & "].vorgang_art" ) ; JSONString ] ;
[ "kurzbeschreibung" ; Let([
	bde=TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].beschreibung_der_erledigung" ) ) ; 1 ; 1 ) ;
	ade=TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].art_der_erledigung" ) ) ; 1 ; 1 )
];
	Case ( not IsEmpty ( bde ) ; bde ; ade )
) ; JSONString ] ;
[ "beschreibung" ; JSONGetElement ( $json ; "[" & $idx & "].beschreibung" ) ; JSONString ] ;
[ "datum" ; Let([
	d_raw=TrimAll(GetAsText(JSONGetElement($json;"["&$idx&"].datum"));1;1);
	d=GetValue(Substitute(d_raw;" ";"¶");1)
];Case(
	IsEmpty(d);"";
	PatternCount(d;"-")=2;Left(d;10);
	PatternCount(d;".")=2;Let([
		p1=Position(d;".";1;1);p2=Position(d;".";1;2);
		day=Left(d;p1-1);mon=Mid(d;p1+1;p2-p1-1);
		yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);
		yr=Case(Length(yr0)=2;"20"&yr0;yr0)
	];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
	"";
	PatternCount(d;"/")=2;Let([
		p1=Position(d;"/";1;1);p2=Position(d;"/";1;2);
		mon=Left(d;p1-1);day=Mid(d;p1+1;p2-p1-1);
		yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);
		yr=Case(Length(yr0)=2;"20"&yr0;yr0)
	];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
	""
)) ; If(IsEmpty(Let([d_raw=TrimAll(GetAsText(JSONGetElement($json;"["&$idx&"].datum"));1;1);d=GetValue(Substitute(d_raw;" ";"¶");1)];Case(IsEmpty(d);"";PatternCount(d;"-")=2;Left(d;10);PatternCount(d;".")=2;Let([p1=Position(d;".";1;1);p2=Position(d;".";1;2);day=Left(d;p1-1);mon=Mid(d;p1+1;p2-p1-1);yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);yr=Case(Length(yr0)=2;"20"&yr0;yr0)];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));PatternCount(d;"/")=2;Let([p1=Position(d;"/";1;1);p2=Position(d;"/";1;2);mon=Left(d;p1-1);day=Mid(d;p1+1;p2-p1-1);yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);yr=Case(Length(yr0)=2;"20"&yr0;yr0)];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));"")));JSONNull;JSONString) ] ;
[ "frist" ; Let([
	d_raw=TrimAll(GetAsText(JSONGetElement($json;"["&$idx&"].frist"));1;1);
	d=GetValue(Substitute(d_raw;" ";"¶");1)
];Case(
	IsEmpty(d);"";
	PatternCount(d;"-")=2;Left(d;10);
	PatternCount(d;".")=2;Let([
		p1=Position(d;".";1;1);p2=Position(d;".";1;2);
		day=Left(d;p1-1);mon=Mid(d;p1+1;p2-p1-1);
		yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);
		yr=Case(Length(yr0)=2;"20"&yr0;yr0)
	];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
	"";
	PatternCount(d;"/")=2;Let([
		p1=Position(d;"/";1;1);p2=Position(d;"/";1;2);
		mon=Left(d;p1-1);day=Mid(d;p1+1;p2-p1-1);
		yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);
		yr=Case(Length(yr0)=2;"20"&yr0;yr0)
	];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
	""
)) ; If(IsEmpty(Let([d_raw=TrimAll(GetAsText(JSONGetElement($json;"["&$idx&"].frist"));1;1);d=GetValue(Substitute(d_raw;" ";"¶");1)];Case(IsEmpty(d);"";PatternCount(d;"-")=2;Left(d;10);PatternCount(d;".")=2;Let([p1=Position(d;".";1;1);p2=Position(d;".";1;2);day=Left(d;p1-1);mon=Mid(d;p1+1;p2-p1-1);yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);yr=Case(Length(yr0)=2;"20"&yr0;yr0)];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));PatternCount(d;"/")=2;Let([p1=Position(d;"/";1;1);p2=Position(d;"/";1;2);mon=Left(d;p1-1);day=Mid(d;p1+1;p2-p1-1);yr0=GetValue(Substitute(Mid(d;p2+1;99);" ";"¶");1);yr=Case(Length(yr0)=2;"20"&yr0;yr0)];yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));"")));JSONNull;JSONString) ] ;
[ "datei_pfad" ; Let([
	dp=TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].datei" ) ) ; 1 ; 1 )
];
	If ( IsEmpty ( dp ) ; "" ; dp )
) ; JSONString ] ;
[ "erledigt" ; Case ( Lower ( JSONGetElement ( $json ; "[" & $idx & "].erledigt" ) ) = "x" or Lower ( JSONGetElement ( $json ; "[" & $idx & "].erledigt" ) ) = "true" or JSONGetElement ( $json ; "[" & $idx & "].erledigt" ) = "1" ; True ; False ) ; JSONBoolean ] ;
[ "ersteller" ; JSONGetElement ( $json ; "[" & $idx & "].ersteller" ) ; JSONString ] ;
[ "verantwortlicher" ; JSONGetElement ( $json ; "[" & $idx & "].verantwortlicher" ) ; JSONString ] ;
[ "sb" ; JSONGetElement ( $json ; "[" & $idx & "].sb" ) ; JSONString ] ;
[ "sync_state" ; "geaendert" ; JSONString ] ;
[ "app_modified_at" ; If ( IsEmpty ( $ts_iso ) ; "1970-01-01T00:00:00Z" ; $ts_iso ) ; JSONString ]
)
